mapper.select:
select role_permission.id, role.role_name, permission.action_code, permission.permission_desc from tb_role_permission role_permission join tb_role role on role_permission.role_id = role.id join tb_permission permission on role_permission.permission_id = permission.id where role_permission.is_delete = 0
and role_permission.role_id = #{rolePermissionPageDTO.roleId}
and role_permission.permission_id = #{rolePermissionPageDTO.permissionId}
